#include <iostream>
#include <vector>
using namespace std;

void solve() {
    int n, m, L, R;
    cin >> n >> m >> L >> R;

    if (1LL * n * L > m || m > 1LL * n * R) {
        cout << -1 << '\n';
        return;
    }

    int base = m / n;
    int extra = m % n;

    vector<pair<int, int>> edges;

    for (int i = 0; i < n; i++) {
        int cnt = base + (i < extra ? 1 : 0);

        for (int j = 0; j < cnt; j++) {
            int u = i + 1;
            int v = (i + j) % n + 1;
            edges.push_back({u, v});
        }
    }

    for (auto &e : edges) {
        cout << e.first << " " << e.second << '\n';
    }
}

int main() {
    int t;
    cin >> t;

    while (t--) {
        solve();
    }

    return 0;
}

